#include "interface.h"
#include <vector>
#include <cstdint>
#include <string>
#include <cstring>

uint64_t kmer_histogram_checksum(const std::string& dna, int k, int iters) {
    const size_t n = dna.size();
    const size_t bins = 1ULL << (2 * k);
    std::vector<uint32_t> dense(bins);

    uint8_t map[256];
    map['A'] = 0; map['C'] = 1; map['G'] = 2; map['T'] = 3;

    uint64_t hash = 0;
    const uint64_t mask = (1ULL << (2 * k)) - 1;

    for (int iter = 0; iter < iters; ++iter) {
        std::memset(dense.data(), 0, bins * sizeof(uint32_t));

        if (n >= (size_t)k) {
            uint64_t current_kmer = 0;
            for (int i = 0; i < k; ++i) {
                current_kmer = (current_kmer << 2) | map[(uint8_t)dna[i]];
            }
            dense[current_kmer]++;

            for (size_t i = k; i < n; ++i) {
                current_kmer = ((current_kmer << 2) | map[(uint8_t)dna[i]]) & mask;
                dense[current_kmer]++;
            }
        }

        uint64_t h = 1469598103934665603ULL;
        for (size_t i = 0; i < bins; ++i) {
            h ^= static_cast<uint64_t>(dense[i]);
            h *= 1099511628211ULL;
        }
        hash = h;
    }
    return hash;
}
